using System;
using System.Collections.Generic;
using System.Text.RegularExpressions;

namespace Eddie.Core
{
	public static class AmneziaCPSDatabase
	{
		public class CPS
		{
			public string Code = "";
			public string Type = "";
			public string I1 = "";
			public string I2 = "";
			public string I3 = "";
			public string I4 = "";
			public string I5 = "";

			public string GetName()
			{
				return Code + " (" + Type + ")";
			}
		}

		private static Dictionary<string, CPS> m_presets = null;
		private static readonly Random m_random = new Random();

		public static void EnsureLoaded()
		{
			if (m_presets == null)
				Load();
		}

		public static void Load()
		{
			m_presets = new Dictionary<string, CPS>();

			string csvData = GetCsvData();
			string[] lines = csvData.Split('\n');

			foreach (string line in lines)
			{
				if (string.IsNullOrWhiteSpace(line))
					continue;

				string[] row = line.Split(',');
				if (row.Length < 3)
					continue;

				string i1 = row[2];
				string i2 = row.Length > 3 ? row[3] : "";
				string i3 = row.Length > 4 ? row[4] : "";
				string i4 = row.Length > 5 ? row[5] : "";
				string i5 = row.Length > 6 ? row[6] : "";

				List<string> compacted = CompactCpsValues(i1, i2, i3, i4, i5);

				CPS cps = new CPS();
				cps.Code = row[0];
				cps.Type = row[1];
				cps.I1 = compacted[0];
				cps.I2 = compacted[1];
				cps.I3 = compacted[2];
				cps.I4 = compacted[3];
				cps.I5 = compacted[4];

				m_presets[cps.Code] = cps;
			}
		}

		public static CPS GetPreset(string code)
		{
			EnsureLoaded();
			if (string.IsNullOrEmpty(code))
				return null;
			if (m_presets.ContainsKey(code))
				return m_presets[code];
			return null;
		}

		public static CPS GetRandomPreset()
		{
			EnsureLoaded();
			if (m_presets == null || m_presets.Count == 0)
				return null;

			List<string> keys = new List<string>(m_presets.Keys);
			return m_presets[keys[m_random.Next(keys.Count)]];
		}

		public static List<string> GetCodes()
		{
			EnsureLoaded();
			List<string> codes = new List<string>();
			codes.Add("");
			foreach (CPS c in m_presets.Values)
				codes.Add(c.Code);
			codes.Sort();
			return codes;
		}

		public static List<string> GetNames()
		{
			EnsureLoaded();
			List<string> names = new List<string>();
			names.Add("");
			foreach (CPS c in m_presets.Values)
				names.Add(c.GetName());
			names.Sort();
			return names;
		}

		private static List<string> CompactCpsValues(string i1, string i2, string i3, string i4, string i5)
		{
			List<string> result = new List<string>();
			Regex regex = new Regex("^<b 0x.*>$");

			i1 = i1.ToLowerInvariant();
			i2 = i2.ToLowerInvariant();
			i3 = i3.ToLowerInvariant();
			i4 = i4.ToLowerInvariant();
			i5 = i5.ToLowerInvariant();

			if (!string.IsNullOrEmpty(i1) && regex.IsMatch(i1)) result.Add(i1);
			if (!string.IsNullOrEmpty(i2) && regex.IsMatch(i2)) result.Add(i2);
			if (!string.IsNullOrEmpty(i3) && regex.IsMatch(i3)) result.Add(i3);
			if (!string.IsNullOrEmpty(i4) && regex.IsMatch(i4)) result.Add(i4);
			if (!string.IsNullOrEmpty(i5) && regex.IsMatch(i5)) result.Add(i5);

			while (result.Count < 5)
				result.Add("");

			return result;
		}

